        var QuemCadValue = 1;
        var filtro = new FilterDocumentos
        {
            QuemCad = QuemCadValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroDocumentos(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var QuemCadParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBDocumentosDicInfo.QuemCad}");
